import React from "react";
import "./CalendarGrid.css";

const days = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

const CalendarGrid = ({ events, filters }) => {
  const filteredEvents = events.filter((e) => filters[e.type]);

  const getEventForDay = (day) =>
    filteredEvents.find((e) => e.date.endsWith(`-${String(day).padStart(2, "0")}`));

  return (
    <>
      <div className="days-row">
        {days.map((day) => (
          <div key={day}>{day}</div>
        ))}
      </div>

      <div className="calendar-grid">
        {[...Array(31)].map((_, i) => {
          const day = i + 1;
          const event = getEventForDay(day);

          return (
            <div
              key={day}
              className={`calendar-cell ${event ? event.type : ""}`}
            >
              <span className="date-number">{day}</span>
              {event && <div className="event-text">{event.title}</div>}
            </div>
          );
        })}
      </div>
    </>
  );
};

export default CalendarGrid;
